DATABASE_URL_ALIASES = ("DATABASE_URL", "PGDATABASE")
DOCKER_COMPOSE_FILE = ROOT / "docker-compose.yml"
PYTHON_SOURCE_DIRS = ("services", "packages", "scripts")


class VerificationError(RuntimeError):
    """Raised when repository verification finds a deterministic failure."""


def rel(path: Path) -> str:
    return path.relative_to(ROOT).as_posix()


def skip(message: str) -> None:
    print(f"SKIP: {message}")


def run(command: list[str], cwd: Path = ROOT, env: dict[str, str] | None = None) -> None:
    print("+", " ".join(command))
    subprocess.run(command, cwd=cwd, env=env, check=True)


def command_available(command: str) -> bool:
    return shutil.which(command) is not None


def path_is_ignored(path: Path) -> bool:
    return bool(IGNORED_PARTS.intersection(path.parts))


def path_is_helm_template(path: Path) -> bool:
    try:
        relative = path.relative_to(HELM_CHART)
    except ValueError:
        return False
    return "templates" in relative.parts


def verify_required_paths() -> None:
    missing = []
    for directory in REQUIRED_DIRECTORIES:
        if not (ROOT / directory).is_dir():
            missing.append(f"{directory.as_posix()}/")
    for file_path in REQUIRED_FILES:
        if not (ROOT / file_path).is_file():
            missing.append(file_path.as_posix())
    for app in FRONTEND_APPS:
        for file_name in ("package.json", "package-lock.json"):
            path = ROOT / app / file_name
            if not path.is_file():
                missing.append(rel(path))
    if missing:
        raise VerificationError("missing required repository paths: " + ", ".join(missing))
    print("verified required project directories and frontend lockfiles")


def validate_json() -> None:
    count = 0
    for path in sorted(ROOT.rglob("*.json")):
        if path_is_ignored(path):
            continue
        with path.open(encoding="utf-8") as handle:
            json.load(handle)
        count += 1
    print(f"validated {count} json files")


def validate_yaml() -> None:
    try:
        import yaml
    except Exception as exc:
        skip(f"yaml validation requires PyYAML ({exc})")
        return

    count = 0
    for pattern in ("*.yaml", "*.yml"):
        for path in sorted(ROOT.rglob(pattern)):
            if path_is_ignored(path) or path_is_helm_template(path):
                continue
            with path.open(encoding="utf-8") as handle:
                yaml.safe_load(handle)
            count += 1
    print(f"validated {count} non-template yaml files")


def run_services() -> None:
    for app in sorted((ROOT / "services").glob("*/app.py")):
        run([sys.executable, str(app)])


def run_frontends() -> None:
    run(["npm", "test"])
    run(["npm", "run", "build"])


def verify_go_sdk() -> None:
    if not command_available("go"):
        skip("go test ./... in packages/sdk-go requires Go")
        return
    run(["go", "test", "./..."], cwd=GO_SDK)


