        raise VerificationError(f"missing Helm chart metadata: {rel(chart)}")
    if not command_available("helm"):
        skip("helm lint requires Helm")
        return
    run(["helm", "lint", str(HELM_CHART)])


def verify_database_schema() -> None:
    schema = ROOT / "database/schema.sql"
    migrations = sorted((ROOT / "database/migrations").glob("*.sql"))
    if not schema.read_text(encoding="utf-8").strip():
        raise VerificationError(f"database schema is empty: {rel(schema)}")
