        raise VerificationError("database migrations are unavailable")
    print(f"verified database schema and {len(migrations)} migrations are available")

    if not command_available("psql"):
        skip("database schema load check requires psql")
        return
    database_url = os.environ.get(DATABASE_URL_ENV) or next(
        (os.environ[name] for name in DATABASE_URL_ALIASES if os.environ.get(name)),
        None,
    )
    if not database_url:
        skip(f"psql is installed, but {DATABASE_URL_ENV} is not set for schema load check")
        return
    env = os.environ.copy()
    env["PGOPTIONS"] = f"{env.get('PGOPTIONS', '')} -c search_path=public".strip()
    run(
        [
            "psql",
            "--set=ON_ERROR_STOP=1",
            "--single-transaction",
            "--file",
            str(schema),
            database_url,
        ],
        env=env,
    )


def docker_compose_command() -> list[str] | None:
    if command_available("docker"):
        result = subprocess.run(
            ["docker", "compose", "version"],
            stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL,
            check=False,
        )
        if result.returncode == 0:
            return ["docker", "compose"]
    if command_available("docker-compose"):
        return ["docker-compose"]
    return None


def verify_docker_inputs() -> None:
    compose_data = DOCKER_COMPOSE_FILE.read_text(encoding="utf-8")
